package j0530;

public class Star2 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
        int i,j;//i(ч),j(滌)
        for(i=1;i<=5;i++) { //ч1~5
        	for(j=5;j>=i;j--) {//滌1~5
        	System.out.print("*");
        	}
        	System.out.println();//還夥翎
        }
	}
}







